const dns = require('dns')
const mongoose = require('mongoose')
const env = require('./env')

// Some Windows/corporate networks refuse SRV lookups through the OS default
// resolver, which breaks `mongodb+srv://` (Atlas) URIs with querySrv ECONNREFUSED.
// Pointing Node at a public resolver makes the SRV lookup succeed reliably.
if (env.dnsServers) {
  dns.setServers(env.dnsServers.split(',').map((s) => s.trim()).filter(Boolean))
}

/**
 * Establish the MongoDB connection. Exits the process on failure so the app
 * never runs in a half-initialised state.
 * @returns {Promise<typeof mongoose>}
 */
async function connectDB() {
  mongoose.set('strictQuery', true)
  try {
    const conn = await mongoose.connect(env.mongoUri)
    // eslint-disable-next-line no-console
    console.log(`✅ MongoDB connected: ${conn.connection.host}`)
    return conn
  } catch (error) {
    // eslint-disable-next-line no-console
    console.error(`❌ MongoDB connection error: ${error.message}`)
    process.exit(1)
  }
}

module.exports = connectDB
